var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"그러니까, 이번 주에 오기로 한 보급품이 운반 도중에 죄다 탈취되었다고?","JPN":"つまり、今週分の補給品が運ばれる途中に全部盗まれただと？","ENG":"Wait, you’re telling me the supplies set to arrive this week were all stolen?","TWN":"你的意思是，原本預計這週會抵達的補給品，在運送過程中遭洗劫一空？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"후방에서 온 무전으로는 그렇답니다.","JPN":"後方からの連絡ではそうらしいです。","ENG":"That’s what the rear is reporting sir.","TWN":"後勤傳來的無線電是這麼說的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"방금 전에 아드님이 약탈당한 수송 차량을 찾으셨다던데, 밀알 한 톨 안 남아 있다더군요.","JPN":"先ほど息子さんが略奪された車両を見つけたそうですが、小麦の一粒も残されていなかったと。","ENG":"A moment ago, your son inspected a looted vehicle. He reported all of the supplies gone, sir.","TWN":"聽說剛才少爺找到遭搶的運輸車，結果裡面連一粒麥子都不剩。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"강경파랑 손잡은 놈이 빼돌린 거겠지. 개수작이 점점 진화하는군.","JPN":"強硬派と手を組んだやつが横取りしたんだろう。ふざけた真似がだんだんひどくなっているな。","ENG":"A soldier from the hardliners likely stole it. I see their dirty tactics are evolving.","TWN":"肯定是和強硬派合作的傢伙幹的！花招越來越多！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"어떡할까요? 보급 없이는 이번 주 배급도 유지하기 어렵습니다.","JPN":"どうしますか？　補給なしでは今週の配給も厳しくなります。","ENG":"What should we do, sir? Without supplies, it will be difficult to follow this week’s distribution schedule.","TWN":"現在怎麼辦？沒有補給品的話，這個禮拜的配給恐怕會有困難。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"끄응, 하여간 빌어먹을 강경파 놈들……. 역시 협정 건은…….","JPN":"ぐぬぬ、くそったれな強硬派め……やはり協定の件は……","ENG":"Huh, damn those bastards from the hardliners... As expected given the current agreement...","TWN":"嗯嗯，那些該死的強硬派……看來還是得跟他們談……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"말씀하시는 도중에 죄송합니다, 대장님.","JPN":"お話中、申し訳ありません、隊長。","ENG":"My apologies for interrupting, captain.","TWN":"隊長，抱歉打斷你們的談話。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"순찰조에서 보고했던 여자가 도착했습니다. 안으로 들일까요?","JPN":"見回り組が報告した女が来ました。中に入れましょうか？","ENG":"The woman the patrol team reported in has arrived, shall I let her in?","TWN":"巡邏隊說的那個女人到了，請她入內嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"오, 그래. 바로 들어오라고 해.","JPN":"お、いいぞ。早く入れろ。","ENG":"Oh, yes. Send her right in.","TWN":"嗯，好，讓她進來。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"보급은 내가 다른 병단들에게 잘 부탁하기로 하지. 대신 배급량도 순찰도 절반으로 줄여.","JPN":"補給は俺が他の兵団に頼むとする。代わりに配給量も見回りも半分にしろ。","ENG":"I’ll request more supplies from other troops, in the meantime, cut all rations by half.","TWN":"補給的事我再去拜託其他兵團，但配給量和巡邏的人數都要減半。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"잘 생각하셨습니다. 좋은 시간 되십시오.","JPN":"それがいいと思います。いいお時間を。","ENG":"Good idea, sir. Understood. Enjoy your evening.","TWN":"隊長英明，那就不耽誤隊長休息。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일 때문에 많이 바쁘신 것 같네요, 자크 님. 여유가 생기실 때 다시 올까요?","JPN":"仕事でだいぶ忙しそうですね、ジャック様。暇な時を見計らって出直しましょうか？","ENG":"You seem so busy with your work, Sir Jacques. Shall I come back another time?","TWN":"札克隊長，你好像很忙的樣子，還是等你方便時我再過來？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"아니야. 거기 앉지. 오느라 고생했어.","JPN":"いや、そこに座れ。よく来てくれた。","ENG":"Of course not. Please, take a seat. Thanks for coming all the way.","TWN":"不需要，你坐，辛苦你來這一趟。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"내 부하들이 건드리거나 하지는 않았나? 요즘 신병들은 기강이 해이해서 말이야.","JPN":"俺の部下たちが手を出したりしなかったか？　最近の新人は気が緩んでいるからな。","ENG":"Did you have any trouble with the men outside? Recruits these days lack discipline.","TWN":"我的手下應該沒有冒犯你吧？最近的新兵軍紀比較渙散一點。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 잠깐 길을 잃었는데 친절하게 안내까지 해 주더라고요.","JPN":"いいえ。少し道に迷ったところを親切に案内までしてくれましたよ。","ENG":"Oh, not at all, sir. I was lost for a bit, but your men gave such wonderful directions.","TWN":"沒有，我找不到路，他們還很親切地幫我指路呢～"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"그래? 순찰조에게 포상이라도 줘야겠군.","JPN":"そうか？ 見回り組に褒美でもやらないとな。","ENG":"Is that so? I suppose I should give them a bonus.","TWN":"是嗎？看來我得打賞巡邏隊囉？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"한동안은 내 침실에서 지내도록 해. 원하는 건 부하들에게 말하면 해결해 줄 거야.","JPN":"しばらくは俺の部屋で暮らせ。欲しいものは部下に言えば解決してくれるだろう。","ENG":"Please, stay in my bedroom for a while. If you need anything at all, tell my men and they will get it for you.","TWN":"你就先暫時住在我的寢室裡，有任何需要可以找我的手下，他們會替你處理。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 신사적이시네요. 보는 눈도 없으니까 원하시는 대로 하셔도 될 텐데.","JPN":"とても紳士的ですね。監視の目もないし、思うままにしてもいいのに。","ENG":"Oh, you’re such a gentleman! I was expecting to do it as you please since there’s no one looking.","TWN":"你真是紳士呢～現在明明又沒有人在看，你想做什麼都可以。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}}]`);export{e as default};